body {
  font-family: serif;
}

/* sans-serif に変えると
   ゴシック体になる */

h1 {
  color: #2d6a4f;
  font-size: 32px;
  font-weight: bold; /* または 700 */
}

/* 数値指定も可能
   300: 細い  400: 標準  700: 太い */

p {
  line-height: 1.8;
}

/* 1.0: 詰まって読みにくい
   1.6〜1.8: 日本語に最適
   2.5: 開きすぎ */

h1 {
  color: #2d6a4f;
  font-size: 32px;
  font-weight: bold;
  letter-spacing: 0.05em;
}

body {
  font-family: "Noto Sans JP", sans-serif;
  color: #333333;
  line-height: 1.8;
}

h1 {
  color: #2d6a4f;
  font-size: 32px;
  letter-spacing: 0.05em;
}

